#include "dimmer_triac.h"
#include <Arduino.h>
#define GATE_PIN 25
#define ZC_PIN 34
static volatile uint8_t _dim=0;
static volatile unsigned long _zcTime=0;
void IRAM_ATTR _zc_isr(){_zcTime=micros();}
void dimmer_setup(){pinMode(GATE_PIN,OUTPUT);pinMode(ZC_PIN,INPUT_PULLUP);attachInterrupt(ZC_PIN,_zc_isr,RISING);Serial.println("[dimmer] OK");}
void dimmer_set(uint8_t p){_dim=constrain(p,0,100);}
uint8_t dimmer_get(){return _dim;}
